--- Compute HMAC-SHA256 for plugin integrity verification
local function compute_hmac(data)
    local hmac_secret = os.getenv(HMAC_SECRET_ENV)
    if not hmac_secret or hmac_secret == "" then
        return nil, "HMAC secret not configured"
    end

    local hmac = require "resty.hmac"
    local h = hmac:new(hmac_secret, hmac.ALGOS.SHA256)
    if not h then
        return nil, "failed to create HMAC instance"
    end

    local ok = h:update(data)
    if not ok then
        return nil, "failed to update HMAC"
    end

    local digest = h:final()
    if not digest then
        return nil, "failed to finalize HMAC"
    end

    return ngx.encode_base64(digest)
end

--- Verify HMAC signature of plugin code
local function verify_hmac(code, signature)
    if not signature or signature == "" then
        return false, "missing signature"
    end

    local expected, err = compute_hmac(code)
    if not expected then
        return false, "HMAC computation failed: " .. (err or "unknown")
    end

    -- Constant-time comparison to prevent timing attacks
    if #expected ~= #signature then
        return false, "signature length mismatch"
    end

    local result = 0
    for i = 1, #expected do
        result = bit.bor(result, bit.bxor(string.byte(expected, i), string.byte(signature, i)))
    end

    if result ~= 0 then
        return false, "signature verification failed"
    end

    return true
end

--- Validate plugin code for dangerous patterns
local function validate_code(code)
    if not code or type(code) ~= "string" then
        return false, "plugin code must be a non-empty string"
    end

    if #code == 0 then
        return false, "plugin code is empty"
    end

    if #code > MAX_CODE_SIZE then
        return false, "plugin code exceeds maximum size of " .. MAX_CODE_SIZE .. " bytes"
    end

    -- Check for null bytes
    if code:find("\0") then
        return false, "plugin code contains null bytes"
    end

    -- Check for dangerous patterns
    local code_lower = code:lower()
    for _, pattern in ipairs(DANGEROUS_PATTERNS) do
        local match_pos = code_lower:find(pattern:lower())
        if match_pos then
            return false, "plugin code contains forbidden pattern near position " .. match_pos
        end
    end

    -- Verify the code is syntactically valid before execution
    local test_fn, parse_err = loadstring(code)
    if not test_fn then
        return false, "plugin code has syntax errors: " .. (parse_err or "unknown")
    end

    return true
end

--- Create a sandboxed environment for plugin execution
local function create_sandbox(plugin_name)
    local env = {}

    -- Copy safe environment
    for k, v in pairs(SAFE_ENV) do
        if type(v) == "table" then
            env[k] = make_readonly(v, k)
        else
            env[k] = v
        end
    end

    -- Provide a plugin-specific context
    env.PLUGIN_NAME = plugin_name

    -- Provide a safe print/log that tags with plugin name
    env.plugin_log = function(level, ...)
        local args = { ... }
        local msg_parts = {}
        for i, arg in ipairs(args) do
            msg_parts[i] = tostring(arg)
        end
        local msg = table.concat(msg_parts, " ")
        -- Sanitize log output to prevent log injection
        msg = msg:gsub("[\r\n]", " ")
        ngx.log(level or ngx.INFO, "[plugin:", plugin_name, "] ", msg)
    end

    return make_readonly(env, "sandbox")
end

--- Connect to Redis with proper error handling
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "failed to connect to Redis: " .. (err or "unknown")
    end

    -- Authenticate if password is configured
    local redis_pass = os.getenv("REDIS_GATEWAY_PASSWORD")
    if redis_pass and redis_pass ~= "" then
        local auth_ok, auth_err = red:auth(redis_pass)
        if not auth_ok then
            red:close()
            return nil, "Redis authentication failed: " .. (auth_err or "unknown")
        end
    end

    return red
end

--- Release Redis connection back to pool
local function release_redis(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "failed to set Redis keepalive: ", err)
        red:close()
    end
end

--- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return nil, nil, err
    end

    -- Load code and signature atomically
    red:init_pipeline()
    red:get(PLUGIN_PREFIX .. plugin_name .. ":code")
    red:get(PLUGIN_PREFIX .. plugin_name .. ":signature")
    red:get(PLUGIN_PREFIX .. plugin_name .. ":version")

    local results, pipeline_err = red:commit_pipeline()
    release_redis(red)

    if not results then
        return nil, nil, "Redis pipeline failed: " .. (pipeline_err or "unknown")
    end

    local code = results[1]
    local signature = results[2]
    local version = results[3]

    if code == ngx.null or not code then
        return nil, nil, "plugin not found in Redis: " .. plugin_name
    end

    if signature == ngx.null then
        signature = nil
    end

    if version == ngx.null then
        version = "unknown"
    end

    return code, signature, nil, version
end

--- Compile and sandbox plugin code
local function compile_plugin(plugin_name, code, signature)
    -- Step 1: Verify the plugin name is in the allowlist
    if not ALLOWED_PLUGINS[plugin_name] then
        return nil, "plugin '" .. plugin_name .. "' is not in the allowed plugins list"
    end

    -- Step 2: Validate code structure and check for dangerous patterns
    local valid, validation_err = validate_code(code)
    if not valid then
        return nil, "code validation failed for plugin '" .. plugin_name .. "': " .. validation_err
    end

    -- Step 3: Verify HMAC signature (integrity check)
    local sig_ok, sig_err = verify_hmac(code, signature)
    if not sig_ok then
        ngx.log(ngx.ERR, "HMAC verification failed for plugin '", plugin_name, "': ", sig_err)
        return nil, "signature verification failed for plugin '" .. plugin_name .. "': " .. sig_err
    end

    -- Step 4: Compile the code
    local fn, compile_err = loadstring(code, "=plugin:" .. plugin_name)
    if not fn then
        return nil, "compilation failed for plugin '" .. plugin_name .. "': " .. compile_err
    end

    -- Step 5: Apply sandbox environment
    local sandbox = create_sandbox(plugin_name)
    setfenv(fn, sandbox)

    return fn
end

--- Execute a compiled plugin function with resource limits
local function execute_plugin(fn, plugin_name, context)
    -- Set up instruction count limit to prevent infinite loops
    local instruction_count = 0
    local function instruction_hook()
        instruction_count = instruction_count + 1
        if instruction_count > MAX_INSTRUCTIONS then
            error("plugin '" .. plugin_name .. "' exceeded maximum instruction count")
        end
    end

    -- Install the debug hook for instruction counting
    debug.sethook(instruction_hook, "", 10000)

    local ok, result = pcall(fn, context)

    -- Remove the debug hook
    debug.sethook()

    if not ok then
        ngx.log(ngx.ERR, "plugin '", plugin_name, "' execution failed: ", tostring(result))
        return nil, "execution failed: " .. tostring(result)
    end

    -- Validate the plugin returned a proper result
    if result ~= nil and type(result) ~= "table" then
        return nil, "plugin must return nil or a table"
    end

    return result
end

--- Plugin cache with TTL to avoid reloading from Redis on every request
local plugin_cache = {}
local CACHE_TTL = 60 -- seconds

local function get_cached_plugin(plugin_name)
    local cached = plugin_cache[plugin_name]
    if cached and (ngx.now() - cached.loaded_at) < CACHE_TTL then
        return cached.fn, nil
    end
    return nil, "not cached"
end

local function cache_plugin(plugin_name, fn)
    plugin_cache[plugin_name] = {
        fn = fn,
        loaded_at = ngx.now(),
    }
end

--- Main entry point: load and execute a plugin by name
function _M.run_plugin(plugin_name, context)
    -- Validate plugin name format (alphanumeric and underscores only)
    if not plugin_name or type(plugin_name) ~= "string" then
        return nil, "invalid plugin name"
    end

    if not plugin_name:match("^[a-z][a-z0-9_]*$") then
        return nil, "plugin name contains invalid characters"
    end

    if #plugin_name > 64 then
        return nil, "plugin name too long"
    end

    -- Check allowlist
    if not ALLOWED_PLUGINS[plugin_name] then
        ngx.log(ngx.WARN, "attempt to load non-allowlisted plugin: ", plugin_name)
        return nil, "plugin not allowed: " .. plugin_name
    end

    -- Check cache first
    local cached_fn, cache_err = get_cached_plugin(plugin_name)
    if cached_fn then
        ngx.log(ngx.DEBUG, "executing cached plugin: ", plugin_name)
        return execute_plugin(cached_fn, plugin_name, context or {})
    end

    -- Load from Redis
    local code, signature, load_err = load_plugin_from_redis(plugin_name)
    if not code then
        ngx.log(ngx.ERR, "failed to load plugin '", plugin_name, "' from Redis: ", load_err)
        return nil, load_err
    end

    -- Compile with sandbox
    local fn, compile_err = compile_plugin(plugin_name, code, signature)
    if not fn then
        ngx.log(ngx.ERR, "failed to compile plugin '", plugin_name, "': ", compile_err)
        return nil, compile_err
    end

    -- Cache the compiled function
    cache_plugin(plugin_name, fn)

    ngx.log(ngx.INFO, "loaded and cached plugin: ", plugin_name)

    -- Execute
    return execute_plugin(fn, plugin_name, context or {})
end

--- Run a chain of plugins in order
function _M.run_plugin_chain(plugin_names, context)
    if not plugin_names or type(plugin_names) ~= "table" then
        return nil, "plugin_names must be a table"
    end

    local ctx = context or {}
    ctx.chain_results = {}

    for i, plugin_name in ipairs(plugin_names) do
        local result, err = _M.run_plugin(plugin_name, ctx)
        if err then
            ngx.log(ngx.ERR, "plugin chain halted at step ", i,
                " (", plugin_name, "): ", err)
            return nil, "chain halted at " .. plugin_name .. ": " .. err
        end

        ctx.chain_results[plugin_name] = result

        -- Check if plugin requested chain termination
        if result and result.stop_chain then
            ngx.log(ngx.INFO, "plugin '", plugin_name, "' requested chain stop")
            break
        end
    end

    return ctx.chain_results
end

--- Invalidate a cached plugin (e.g., after update)
function _M.invalidate_cache(plugin_name)
    if plugin_name then
        plugin_cache[plugin_name] = nil
        ngx.log(ngx.INFO, "invalidated cache for plugin: ", plugin_name)
    else
        plugin_cache = {}
        ngx.log(ngx.INFO, "invalidated entire plugin cache")
    end
    return true
end

--- List allowed plugins
function _M.list_allowed_plugins()
    local names = {}
    for name, _ in pairs(ALLOWED_PLUGINS) do
        names[#names + 1] = name
    end
    table.sort(names)
    return names
end

--- Admin endpoint handler for plugin management
function _M.admin_handler()
    -- This should only be accessible via internal/authenticated routes
    local method = ngx.req.get_method()

    if method == "GET" then
        -- List plugins
        local plugins = _M.list_allowed_plugins()
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            allowed_plugins = plugins,
            cache_entries = (function()
                local count = 0
                for _ in pairs(plugin_cache) do count = count + 1 end
                return count
            end)(),
        }))
        return

    elseif method == "DELETE" then
        -- Invalidate cache
        local args = ngx.req.get_uri_args()
        local plugin_name = args.plugin
        if plugin_name and type(plugin_name) == "string" then
            if not plugin_name:match("^[a-z][a-z0-9_]*$") then
                ngx.status = ngx.HTTP_BAD_REQUEST
                ngx.say(cjson.encode({ error = "invalid plugin name format" }))
                return
            end
            _M.invalidate_cache(plugin_name)
        else
            _M.invalidate_cache()
        end
        ngx.say(cjson.encode({ status = "cache invalidated" }))
        return

    else
        ngx.status = 405
        ngx.say(cjson.encode({ error = "method not allowed" }))
        return
    end
end

--- Request handler: determine which plugins to run and execute them
function _M.access_handler()
    -- Determine plugin chain from route configuration (stored in Redis or nginx vars)
    local plugin_chain_str = ngx.var.plugin_chain
    if not plugin_chain_str or plugin_chain_str == "" then
        -- No plugins configured for this route
        return
    end

    -- Parse comma-separated plugin names
    local plugin_names = {}
    for name in plugin_chain_str:gmatch("([^,]+)") do
        name = name:match("^%s*(.-)%s*$") -- trim whitespace
        if name ~= "" then
            plugin_names[#plugin_names + 1] = name
        end
    end

    if #plugin_names == 0 then
        return
    end

    -- Build request context
    local context = {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = ngx.req.get_uri_args(),
        headers = ngx.req.get_headers(),
        remote_addr = ngx.var.remote_addr,
        timestamp = ngx.now(),
    }

    -- Execute plugin chain
    local results, err = _M.run_plugin_chain(plugin_names, context)
    if err then
        ngx.log(ngx.ERR, "plugin chain error: ", err)
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "internal gateway error" }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- Process plugin results (e.g., set headers, modify status)
    if results then
        for plugin_name, result in pairs(results) do
            if type(result) == "table" then
                -- Plugin can set response headers
                if result.headers and type(result.headers) == "table" then
                    for k, v in pairs(result.headers) do
                        if type(k) == "string" and type(v) == "string" then
                            ngx.req.set_header(k, v)
                        end
                    end
                end

                -- Plugin can reject the request
                if result.reject then
                    local status = tonumber(result.status) or ngx.HTTP_FORBIDDEN
                    local message = type(result.message) == "string" and result.message or "request rejected"
                    ngx.status = status
                    ngx.header["Content-Type"] = "application/json"
                    ngx.say(cjson.encode({
                        error = message,
                        rejected_by = plugin_name,
                    }))
                    return ngx.exit(status)
                end
            end
        end
    end
end

return _M